<?php
namespace App\Domain\Equipment;use App\Domain\Equipment\Data\CharacterEquipmentEntry;use App\Domain\Equipment\Data\CharacterEquipmentSummary;use App\Domain\Inventory\Instances\ItemInstanceStatus;use App\Domain\Media\MediaAssetType;use App\Models\Character;use App\Models\Item;use InvalidArgumentException;
final class CharacterEquipmentSummaryService{private $validator;public function __construct(EquippableItemValidator $validator){$this->validator=$validator;}public function snapshot(Character $character){$rows=$character->equipment()->with('itemInstance')->orderBy('id')->get();$itemIds=$rows->map(function($row){return$row->itemInstance?$row->itemInstance->item_id:null;})->filter()->unique();$items=$itemIds->isEmpty()?collect():Item::whereIn('id',$itemIds)->with(['mediaAssets'=>function($q){$q->where('asset_type',MediaAssetType::ICON)->orderByDesc('is_primary')->orderBy('sort_order')->orderBy('id');}])->get()->keyBy('id');$bySlot=$rows->keyBy('slot');$entries=[];foreach(CharacterEquipmentSlot::all() as $slot){$row=$bySlot->get($slot);if(!$row){$entries[]=new CharacterEquipmentEntry(['slot'=>$slot,'slot_label'=>CharacterEquipmentSlot::label($slot),'occupied'=>false,'item_instance_uuid'=>null,'public_reference'=>null,'item_id'=>null,'item_code'=>null,'item_name'=>null,'refinement_level'=>null,'status'=>null,'icon_url'=>null,'bonuses'=>[]]);continue;}$instance=$row->itemInstance;$item=$instance?$items->get($instance->item_id):null;if(!$instance||!$item||(int)$instance->character_id!==(int)$character->id||$instance->status!==ItemInstanceStatus::EQUIPPED)throw new InvalidArgumentException('Inconsistent character equipment state.');$this->validator->assertCompatible($item,$slot);$asset=$item->mediaAssets->first();$entries[]=new CharacterEquipmentEntry(['slot'=>$slot,'slot_label'=>CharacterEquipmentSlot::label($slot),'occupied'=>true,'item_instance_uuid'=>$instance->uuid,'public_reference'=>strtoupper(substr(str_replace('-','',$instance->uuid),0,8)),'item_id'=>(int)$item->id,'item_code'=>$item->code,'item_name'=>$item->name,'refinement_level'=>(int)$instance->refinement_level,'status'=>$instance->status,'icon_url'=>$asset?$asset->url():null,'bonuses'=>$this->validator->bonuses($item)->toArray()]);}return new CharacterEquipmentSummary($entries);}}
